import { geo, geoFromHeaders, isInRegion, geoDistance } from './geo'

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function makeHeaders(pairs: Record<string, string>): Headers {
  return new Headers(pairs)
}

// ---------------------------------------------------------------------------
// geoFromHeaders
// ---------------------------------------------------------------------------

describe('geoFromHeaders', () => {
  it('extracts all Vercel headers', () => {
    const headers = makeHeaders({
      'x-vercel-ip-city': 'San Francisco',
      'x-vercel-ip-country': 'US',
      'x-vercel-ip-country-region': 'CA',
      'x-vercel-ip-latitude': '37.7749',
      'x-vercel-ip-longitude': '-122.4194',
      'x-vercel-ip-timezone': 'America/Los_Angeles',
    })

    const result = geoFromHeaders(headers)

    expect(result.city).toBe('San Francisco')
    expect(result.countryCode).toBe('US')
    expect(result.country).toBe('United States')
    expect(result.region).toBe('CA')
    expect(result.latitude).toBe('37.7749')
    expect(result.longitude).toBe('-122.4194')
    expect(result.timezone).toBe('America/Los_Angeles')
  })

  it('falls back to cf-ipcountry when x-vercel-ip-country is absent', () => {
    const headers = makeHeaders({
      'cf-ipcountry': 'GB',
    })

    const result = geoFromHeaders(headers)

    expect(result.countryCode).toBe('GB')
    expect(result.country).toBe('United Kingdom')
  })

  it('prefers x-vercel-ip-country over cf-ipcountry when both are present', () => {
    const headers = makeHeaders({
      'x-vercel-ip-country': 'DE',
      'cf-ipcountry': 'FR',
    })

    const result = geoFromHeaders(headers)

    expect(result.countryCode).toBe('DE')
    expect(result.country).toBe('Germany')
  })

  it('returns undefined fields when no headers are present', () => {
    const result = geoFromHeaders(new Headers())

    expect(result.city).toBeUndefined()
    expect(result.countryCode).toBeUndefined()
    expect(result.country).toBeUndefined()
    expect(result.region).toBeUndefined()
    expect(result.latitude).toBeUndefined()
    expect(result.longitude).toBeUndefined()
    expect(result.timezone).toBeUndefined()
  })

  it('returns undefined country when countryCode is unknown', () => {
    const headers = makeHeaders({
      'x-vercel-ip-country': 'ZZ',
    })

    const result = geoFromHeaders(headers)

    expect(result.countryCode).toBe('ZZ')
    expect(result.country).toBeUndefined()
  })

  it('looks up country names for all known country codes', () => {
    const cases: Array<[string, string]> = [
      ['AU', 'Australia'],
      ['BR', 'Brazil'],
      ['CA', 'Canada'],
      ['CN', 'China'],
      ['DE', 'Germany'],
      ['FR', 'France'],
      ['GB', 'United Kingdom'],
      ['IN', 'India'],
      ['JP', 'Japan'],
      ['US', 'United States'],
    ]

    for (const [code, name] of cases) {
      const result = geoFromHeaders(makeHeaders({ 'x-vercel-ip-country': code }))
      expect(result.countryCode).toBe(code)
      expect(result.country).toBe(name)
    }
  })

  it('handles partial headers gracefully', () => {
    const headers = makeHeaders({
      'x-vercel-ip-country': 'JP',
      'x-vercel-ip-city': 'Tokyo',
    })

    const result = geoFromHeaders(headers)

    expect(result.countryCode).toBe('JP')
    expect(result.country).toBe('Japan')
    expect(result.city).toBe('Tokyo')
    expect(result.region).toBeUndefined()
    expect(result.latitude).toBeUndefined()
    expect(result.longitude).toBeUndefined()
    expect(result.timezone).toBeUndefined()
  })
})

// ---------------------------------------------------------------------------
// geo
// ---------------------------------------------------------------------------

describe('geo', () => {
  it('delegates to geoFromHeaders via { headers } destructuring', () => {
    const headers = makeHeaders({
      'x-vercel-ip-country': 'AU',
      'x-vercel-ip-city': 'Sydney',
    })

    const result = geo({ headers })

    expect(result.countryCode).toBe('AU')
    expect(result.country).toBe('Australia')
    expect(result.city).toBe('Sydney')
  })

  it('returns all undefined fields when headers object is empty', () => {
    const result = geo({ headers: new Headers() })

    expect(result.countryCode).toBeUndefined()
    expect(result.country).toBeUndefined()
    expect(result.city).toBeUndefined()
  })
})

// ---------------------------------------------------------------------------
// isInRegion
// ---------------------------------------------------------------------------

describe('isInRegion', () => {
  it('returns true when countryCode is in the regions list', () => {
    expect(isInRegion({ countryCode: 'US' }, ['US', 'CA', 'MX'])).toBe(true)
  })

  it('returns true with case-insensitive comparison (lowercase input)', () => {
    expect(isInRegion({ countryCode: 'us' }, ['US'])).toBe(true)
  })

  it('returns true with case-insensitive comparison (lowercase region list)', () => {
    expect(isInRegion({ countryCode: 'US' }, ['us'])).toBe(true)
  })

  it('returns true with mixed-case inputs', () => {
    expect(isInRegion({ countryCode: 'Gb' }, ['gB'])).toBe(true)
  })

  it('returns false when countryCode is not in the regions list', () => {
    expect(isInRegion({ countryCode: 'DE' }, ['US', 'CA', 'MX'])).toBe(false)
  })

  it('returns false when countryCode is undefined', () => {
    expect(isInRegion({}, ['US', 'CA'])).toBe(false)
  })

  it('returns false when regions list is empty', () => {
    expect(isInRegion({ countryCode: 'US' }, [])).toBe(false)
  })

  it('returns true for a single-element list that matches', () => {
    expect(isInRegion({ countryCode: 'FR' }, ['FR'])).toBe(true)
  })
})

// ---------------------------------------------------------------------------
// geoDistance (Haversine)
// ---------------------------------------------------------------------------

describe('geoDistance', () => {
  it('calculates New York to London within 50 km of ~5570 km', () => {
    // New York:  40.7128° N, 74.0060° W
    // London:   51.5074° N,  0.1278° W
    const distance = geoDistance('40.7128', '-74.0060', '51.5074', '-0.1278')
    expect(distance).toBeGreaterThan(5520)
    expect(distance).toBeLessThan(5620)
  })

  it('returns ~0 km for identical coordinates', () => {
    const distance = geoDistance('48.8566', '2.3522', '48.8566', '2.3522')
    expect(distance).toBeCloseTo(0, 5)
  })

  it('calculates Sydney to Tokyo within 50 km of ~7823 km', () => {
    // Sydney: -33.8688° S, 151.2093° E
    // Tokyo:   35.6762° N, 139.6503° E
    const distance = geoDistance(
      '-33.8688',
      '151.2093',
      '35.6762',
      '139.6503'
    )
    expect(distance).toBeGreaterThan(7773)
    expect(distance).toBeLessThan(7873)
  })

  it('is symmetric (A→B equals B→A)', () => {
    const ab = geoDistance('40.7128', '-74.0060', '51.5074', '-0.1278')
    const ba = geoDistance('51.5074', '-0.1278', '40.7128', '-74.0060')
    expect(ab).toBeCloseTo(ba, 6)
  })
})

